import { Button, Flex, Image, Text, Box, Heading } from "@chakra-ui/react";
import sectionImage from "../../asset/sectionImage.png";
import { useNavigate } from "react-router-dom";

const Section6 = () => {
  const navigate = useNavigate();

  return (
    <Flex
      align="center"
      justify="space-between"
      py={20}
      px={5}
      direction={{ base: "column", md: "row" }}
      gap={10}
    >
      {/* LEFT IMAGE */}
      <Box maxW="500px">
        <Image src={sectionImage} alt="learning" borderRadius="lg" />
      </Box>

      {/* RIGHT CONTENT */}
      <Box maxW="500px">
        <Heading size="lg" mb={4}>
          Transform your career with{" "}
          <span style={{ color: "#A435F0" }}>SRM</span>
        </Heading>

        <Text color="gray.600" mb={4}>
          Join thousands of learners who are already improving their skills and
          advancing their careers.
        </Text>

        {/* BULLETS */}
        <Box mb={6}>
          <Text mb={2}>✔ 87% reported career growth</Text>
          <Text mb={2}>✔ Learn from industry experts</Text>
          <Text>✔ Flexible online courses</Text>
        </Box>

        {/* BUTTON */}
        <Button
          bg="#A435F0"
          color="white"
          size="lg"
          _hover={{ bg: "#8710d8" }}
          onClick={() => navigate("/signup")}
        >
          Get started
        </Button>
      </Box>
    </Flex>
  );
};

export default Section6;
